func AuthenticateAdminCli(t testing.TB, ctx context.Context) {
	c, err := loadConfig()
	require.NoError(t, err)

	AuthenticateCli(t, ctx, c.AdminLoginName, c.AdminLoginPassword)
}

func AddHostToHostSetCli(t testing.TB, hostSetId string, hostId string, ctx context.Context) {
	output := e2e.RunCommand(ctx, "boundary",
		e2e.WithArgs("host-sets", "add-hosts", "-id", hostSetId, "-host", hostId),
	)
	require.NoError(t, output.Err, string(output.Stderr))
}

func AddHostSourceToTargetCli(t testing.TB, targetId string, hostSourceId string, ctx context.Context) {
	output := e2e.RunCommand(ctx, "boundary",
		e2e.WithArgs("targets", "add-host-sources", "-id", targetId, "-host-source", hostSourceId),
	)
	require.NoError(t, output.Err, string(output.Stderr))
}

func SetAccountToUserCli(t testing.TB, userId string, accountId string, ctx context.Context) {
	output := e2e.RunCommand(ctx, "boundary",
		e2e.WithArgs(
			"users", "set-accounts",
			"-id", userId,
			"-account", accountId,
		),
	)
	require.NoError(t, output.Err, string(output.Stderr))
}

